     auto bal = GetBalance(wallet); // Cache
 
-    bench.setup([&] {
-            if (set_dirty) wallet.MarkDirty();
-        })
+    bench.epochIterations(1)
+        .setup([&] { if (set_dirty) wallet.MarkDirty(); })
         .run([&] {
             bal = GetBalance(wallet);
             if (add_mine) assert(bal.m_mine_trusted > 0);
